-- =============================================================================
-- Colors & Hyprbars (hyprland/colors.conf → Lua)
-- Generated by matugen from Material You palette (khi đổi wallpaper)
-- NOTE: Hyprland 0.55+ required for Lua config
--
-- conf reference:
--   # general {
--   #     col.active_border = rgba(869395AA)
--   #     col.inactive_border = rgba(3c494bAA)
--   # }
--
-- Hyprbars: repeated `hyprbars-button` in hyprlang is NOT valid inside
-- hl.config plugin.hyprbars in Lua — use hl.plugin.hyprbars.add_button().
-- See: https://github.com/hyprwm/hyprland-plugins/blob/main/hyprbars/README.md
--
-- Pinned border: match.pin + border_color; gradient = chuỗi rgba (Lua number
-- 0x00…… bị cắt byte cao).
--
-- Plugin options chỉ set khi hyprbars đã load — nếu không sẽ "unknown config key".
-- =============================================================================

local function plugin_is_loaded(needle)
    local ok, plugins = pcall(function() return hl.get_loaded_plugins() end)
    if not ok or type(plugins) ~= "table" then return false end
    local n = needle:lower()
    for _, p in pairs(plugins) do
        local name = type(p) == "table" and (p.name or p.handle or p.path or "") or tostring(p)
        if type(name) == "string" and name:lower():find(n, 1, true) then
            return true
        end
    end
    return false
end

-- misc.background_color (colors.conf) — chuỗi rgba tránh mất nibble
hl.config({
    misc = {
        background_color = "rgba(091517FF)",
    },
})

local function apply_hyprbars_config()
    if not plugin_is_loaded("hyprbars") then return false end

    hl.config({
        plugin = {
            hyprbars = {
                -- Honestly idk if it works like css, but well, why not
                bar_text_font    = "Rubik, Geist, AR One Sans, Reddit Sans, Inter, Roboto, Ubuntu, Noto Sans, sans-serif",
                bar_height       = 30,
                bar_padding      = 10,
                bar_button_padding = 5,
                bar_precedence_over_border = true,
                bar_part_of_window = true,

                -- Use a slightly elevated surface for better separation from the wallpaper/background
                bar_color        = "rgba(111e1fFF)",
                col              = { text = "rgba(d7e5e7FF)" },
            },
        },
    })

    -- example buttons (R -> L)
    -- hyprbars-button = color, size, on-click
    local hb = hl.plugin and hl.plugin.hyprbars
    if hb and type(hb.add_button) == "function" then
        hb.add_button({
            bg_color = "rgb(d7e5e7)",
            size     = 13,
            icon     = "󰖭",
            action   = "hyprctl dispatch 'hl.dsp.window.close()'",
        })
        hb.add_button({
            bg_color = "rgb(d7e5e7)",
            size     = 13,
            icon     = "󰖯",
            action   = "hyprctl dispatch 'hl.dsp.window.fullscreen({ mode = 1 })'",
        })
        hb.add_button({
            bg_color = "rgb(d7e5e7)",
            size     = 13,
            icon     = "󰖰",
            action   = "hyprctl dispatch 'hl.dsp.window.move({ workspace = \"special\", silent = true })'",
        })
    end
    return true
end

if not apply_hyprbars_config() then
    hl.on("hyprland.start", function()
        hl.timer(function()
            apply_hyprbars_config()
        end, { timeout = 2500, type = "oneshot" })
    end)
end

-- windowrulev3 = bordercolor rgba(00dbecAA) rgba(00dbec77),pinned:1
hl.window_rule({
    name  = "pin-border",
    match = { pin = true },
    border_color = { colors = { "rgba(00dbecaa)", "rgba(00dbec77)" } },
})
